+ int holdsock(struct filedesc *fdp, int fdes, struct file **fpp)
+ {
+         register struct file *fp = NULL;
+         int error = 0;
+
+         if ((unsigned)fdes >= fdp->fd_nfiles ||
+             (fp = fdp->fd_ofiles[fdes]) == NULL) {
+                 error = EBADF;
+         } else if (fp->f_type != DTYPE_SOCKET) {
+                 error = ENOTSOCK;
+                 fp = NULL;
+         } else {
+                 fhold(fp);
+         }
+         *fpp = fp;
+         return(error);
+ }
